   137→/**
   138→ * All listener manager stats. @see stats_macros.h
   139→ */
   140→#define ALL_LISTENER_MANAGER_STATS(COUNTER, GAUGE)                                                 \
   141→  COUNTER(listener_added)                                                                          \
   142→  COUNTER(listener_create_failure)                                                                 \
   143→  COUNTER(listener_create_success)                                                                 \
   144→  COUNTER(listener_in_place_updated)                                                               \
