   211→
   212→  // Server::ListenerManager
   213→  absl::StatusOr<bool> addOrUpdateListener(const envoy::config::listener::v3::Listener& config,
   214→                                           const std::string& version_info,
   215→                                           bool added_via_api) override;
   216→  void createLdsApi(const envoy::config::core::v3::ConfigSource& lds_config,
   217→                    const xds::core::v3::ResourceLocator* lds_resources_locator) override {
   218→    ASSERT(lds_api_ == nullptr);
   219→    lds_api_ = factory_->createLdsApi(lds_config, lds_resources_locator);
   220→  }
   221→  std::vector<std::reference_wrapper<Network::ListenerConfig>>
   222→  listeners(ListenerState state = ListenerState::ACTIVE) override;
   223→  uint64_t numConnections() const override;
   224→  bool removeListener(const std::string& listener_name) override;
   225→  void startWorkers(OptRef<GuardDog> guard_dog, std::function<void()> callback) override;
   226→  void stopListeners(StopListenersType stop_listeners_type,
   227→                     const Network::ExtraShutdownListenerOptions& options) override;
   228→  void stopWorkers() override;
   229→  void beginListenerUpdate() override { error_state_tracker_.clear(); }
   230→  void endListenerUpdate(FailureStates&& failure_state) override;
   231→  bool isWorkerStarted() override { return workers_started_; }
   232→  Http::Context& httpContext() { return server_.httpContext(); }
   233→  ApiListenerOptRef apiListener() override;
   234→
   235→  Quic::QuicStatNames& quicStatNames() { return quic_stat_names_; }
   236→
   237→  Instance& server_;
   238→  std::unique_ptr<ListenerComponentFactory> factory_;
   239→
   240→private:
   241→  using ListenerList = std::list<ListenerImplPtr>;
   242→  /**
   243→   * Callback invoked when a listener initialization is completed on worker.
   244→   */
   245→  using ListenerCompletionCallback = std::function<void()>;
   246→
   247→  bool addOrUpdateListenerInternal(const envoy::config::listener::v3::Listener& config,
   248→                                   const std::string& version_info, bool added_via_api,
   249→                                   const std::string& name);
   250→  bool removeListenerInternal(const std::string& listener_name, bool dynamic_listeners_only);
   251→
   252→  struct DrainingListener {
   253→    DrainingListener(ListenerImplPtr&& listener, uint64_t workers_pending_removal)
   254→        : listener_(std::move(listener)), workers_pending_removal_(workers_pending_removal) {}
   255→
   256→    ListenerImplPtr listener_;
   257→    uint64_t workers_pending_removal_;
   258→  };
   259→
   260→  bool doFinalPreWorkerListenerInit(ListenerImpl& listener);
   261→  void addListenerToWorker(Worker& worker, absl::optional<uint64_t> overridden_listener,
   262→                           ListenerImpl& listener, ListenerCompletionCallback completion_callback);
   263→
   264→  ProtobufTypes::MessagePtr dumpListenerConfigs(const Matchers::StringMatcher& name_matcher);
   265→  static ListenerManagerStats generateStats(Stats::Scope& scope);
   266→  static bool hasListenerWithDuplicatedAddress(const ListenerList& list,
   267→                                               const ListenerImpl& listener);
   268→  void updateWarmingActiveGauges() {
   269→    // Using set() avoids a multiple modifiers problem during the multiple processes phase of hot
   270→    // restart.
   271→    stats_.total_listeners_warming_.set(warming_listeners_.size());
   272→    stats_.total_listeners_active_.set(active_listeners_.size());
   273→  }
   274→  bool listenersStopped(const envoy::config::listener::v3::Listener& config) {
   275→    // Currently all listeners in a given direction are stopped because of the way admin
   276→    // drain_listener functionality is implemented. This needs to be revisited, if that changes - if
   277→    // we support drain by listener name,for example.
   278→    return stop_listeners_type_ == StopListenersType::All ||
   279→           (stop_listeners_type_ == StopListenersType::InboundOnly &&
   280→            config.traffic_direction() == envoy::config::core::v3::INBOUND);
   281→  }
   282→  void incListenerCreateFailureStat() {
   283→    // TODO(mattklein123): Now that we no longer create sockets and apply options on workers,
   284→    // this stat is confusingly named and should be more specific, however it's unclear if it's
   285→    // worth changing.
   286→    stats_.listener_create_failure_.inc();
   287→  }
   288→
   289→  /**
   290→   * Mark a listener for draining. The listener will no longer be considered active but will remain
   291→   * present to allow connection draining.
   292→   * @param listener supplies the listener to drain.
   293→   */
   294→  void drainListener(ListenerImplPtr&& listener);
   295→
   296→  /**
   297→   * Start to draining filter chains that are owned by draining listener but not owned by
   298→   * new_listener. The new listener should have taken over the listener socket and partial of the
   299→   * filter chains from listener. This method is used by in place filter chain update.
   300→   * @param draining_listener supplies the listener to be replaced.
   301→   * @param new_listener supplies the new listener config which is going to replace the draining
   302→   * listener.
   303→   */
   304→  void drainFilterChains(ListenerImplPtr&& draining_listener, ListenerImpl& new_listener);
   305→
   306→  /**
   307→   * Stop a listener. The listener will stop accepting new connections and its socket will be
   308→   * closed.
   309→   * @param listener supplies the listener to stop.
   310→   * @param options additional options to be passed through to shutdownListener.
   311→   * @param completion supplies the completion to be called when all workers are stopped accepting
   312→   * new connections. This completion is called on the main thread.
   313→   */
   314→  void stopListener(Network::ListenerConfig& listener,
   315→                    const Network::ExtraShutdownListenerOptions& options,
   316→                    std::function<void()> completion);
   317→
   318→  /**
   319→   * Get a listener by name. This routine is used because listeners have inherent order in static
   320→   * configuration and especially for tests. Thus, we can't use a map.
   321→   * @param listeners supplies the listener list to look in.
   322→   * @param name supplies the name to search for.
   323→   */
   324→  ListenerList::iterator getListenerByName(ListenerList& listeners, const std::string& name);
   325→
   326→  void setNewOrDrainingSocketFactory(const std::string& name, ListenerImpl& listener);
   327→  void createListenSocketFactory(ListenerImpl& listener);
   328→
   329→  void maybeCloseSocketsForListener(ListenerImpl& listener);
   330→  void setupSocketFactoryForListener(ListenerImpl& new_listener,
   331→                                     const ListenerImpl& existing_listener);
   332→
   333→  ApiListenerPtr api_listener_;
   334→  // Active listeners are listeners that are currently accepting new connections on the workers.
   335→  ListenerList active_listeners_;
   336→  // Warming listeners are listeners that may need further initialization via the listener's init
   337→  // manager. For example, RDS, or in the future KDS. Once a listener is done warming it will
   338→  // be transitioned to active.
   339→  ListenerList warming_listeners_;
   340→  // Draining listeners are listeners that are in the process of being drained and removed. They
   341→  // go through two phases where first the workers stop accepting new connections and existing
   342→  // connections are drained. Then after that time period the listener is removed from all workers
   343→  // and any remaining connections are closed.
   344→  std::list<DrainingListener> draining_listeners_;
   345→  std::list<DrainingFilterChainsManager> draining_filter_chains_manager_;
   346→
   347→  std::vector<WorkerPtr> workers_;
   348→  bool workers_started_{};
   349→  absl::optional<StopListenersType> stop_listeners_type_;
   350→  Stats::ScopeSharedPtr scope_;
   351→  ListenerManagerStats stats_;
   352→  ConfigTracker::EntryOwnerPtr config_tracker_entry_;
   353→  LdsApiPtr lds_api_;
   354→  const bool enable_dispatcher_stats_{};
   355→  using UpdateFailureState = envoy::admin::v3::UpdateFailureState;
   356→  absl::flat_hash_map<std::string, std::unique_ptr<UpdateFailureState>> error_state_tracker_;
   357→  FailureStates overall_error_state_;
   358→  Quic::QuicStatNames& quic_stat_names_;
   359→};
