   324→  ListenerList::iterator getListenerByName(ListenerList& listeners, const std::string& name);
   325→
   326→  void setNewOrDrainingSocketFactory(const std::string& name, ListenerImpl& listener);
   327→  void createListenSocketFactory(ListenerImpl& listener);
   328→
   329→  void maybeCloseSocketsForListener(ListenerImpl& listener);
   330→  void setupSocketFactoryForListener(ListenerImpl& new_listener,
