   172→                             Logger::Loggable<Logger::Id::conn_handler> {
   173→  ActiveTcpConnection(ActiveConnections& active_connections,
   174→                      Network::ConnectionPtr&& new_connection, TimeSource& time_system,
   175→                      std::unique_ptr<StreamInfo::StreamInfo>&& stream_info);
   176→  ~ActiveTcpConnection() override;
   177→  // Network::ConnectionCallbacks
   178→  void onEvent(Network::ConnectionEvent event) override;
   179→  void onAboveWriteBufferHighWatermark() override {}
   180→  void onBelowWriteBufferLowWatermark() override {}
   181→
   182→  std::unique_ptr<StreamInfo::StreamInfo> stream_info_;
   183→  ActiveConnections& active_connections_;
   184→  Network::ConnectionPtr connection_;
   185→  Stats::TimespanPtr conn_length_;
   186→};
   187→
   188→using ActiveConnectionPtr = std::unique_ptr<ActiveTcpConnection>;
   189→using ActiveConnectionCollectionPtr = std::unique_ptr<ActiveConnections>;
   190→
   191→// The mixin that handles the composition type ActiveConnectionCollection. This mixin
   192→// provides the connection removal helper and the filter chain removal helper.
   193→// All the prod stream listeners should inherit from this class and leave ActiveStreamListenerBase
   194→// for unit test only.
   195→class OwnedActiveStreamListenerBase : public ActiveStreamListenerBase {
   196→public:
   197→  OwnedActiveStreamListenerBase(Network::ConnectionHandler& parent, Event::Dispatcher& dispatcher,
   198→                                Network::ListenerPtr&& listener, Network::ListenerConfig& config)
   199→      : ActiveStreamListenerBase(parent, dispatcher, std::move(listener), config) {}
   200→
   201→  /**
   202→   * Remove and destroy an active connection.
   203→   * @param connection supplies the connection to remove.
   204→   */
   205→  void removeConnection(ActiveTcpConnection& connection);
   206→
   207→protected:
   208→  /**
   209→   * Return the active connections container attached to the given filter chain.
   210→   */
   211→  ActiveConnections& getOrCreateActiveConnections(const Network::FilterChain& filter_chain);
   212→
   213→  /**
   214→   * Remove an filter chain. All the active connections that are attached to the filter chain will
   215→   * be destroyed.
   216→   * @param filter_chain supplies the filter chain to remove.
   217→   */
   218→  void removeFilterChain(const Network::FilterChain* filter_chain) override;
   219→
   220→  absl::flat_hash_map<const Network::FilterChain*, ActiveConnectionCollectionPtr>
   221→      connections_by_context_;
